     <AiBehavioralSection checkpoints={checkpoints} />
     <AiTemporalSection checkpoints={checkpoints} />
   </div>

   <script>
     import { renderDashboard } from '../lib/utils/ai-dashboard-renderer';
     import { fetchCheckpointsCache } from '../lib/utils/github-checkpoints';
     import {
       filterRenderableCheckpoints,
       formatCheckpointOptionLabel,
       formatGeneratedAt,
     } from '../lib/utils/ai-metrics-utils';
     import type { CheckpointMeta, CheckpointsCache } from '../lib/utils/ai-metrics-utils';

     const dataEl = document.getElementById('checkpoints-data');
     const selector = document.getElementById('checkpoint-selector') as HTMLSelectElement | null;
     const refreshButton = document.getElementById('refresh-metrics-button') as HTMLButtonElement | null;
     const statusEl = document.getElementById('metrics-refresh-status');
     const repoEl = document.getElementById('metrics-repo');
     const branchEl = document.getElementById('metrics-branch');
     const countEl = document.getElementById('metrics-checkpoint-count');
     const generatedEl = document.getElementById('metrics-generated');

     let allCheckpoints: CheckpointMeta[] = dataEl ? JSON.parse(dataEl.dataset.value ?? '[]') : [];

     function setStatus(message: string, tone: 'muted' | 'success' | 'error' = 'muted') {
       if (!statusEl) return;

       const toneClass =
         tone === 'success'
           ? 'text-status-live'
           : tone === 'error'
             ? 'text-status-stale'
             : 'text-text-muted';

       statusEl.className = `font-label text-xs ${toneClass}`;
       statusEl.textContent = message;
     }

     function getSelectedCheckpoints(): CheckpointMeta[] {
       if (!selector || selector.value === 'all') {
         return allCheckpoints;
       }

       return allCheckpoints.filter((checkpoint) => checkpoint.checkpoint_id === selector.value);
     }

     function syncSelector(selectedValue: string) {
       if (!selector) return;

       selector.innerHTML = '';

       const allOption = document.createElement('option');
       allOption.value = 'all';
       allOption.textContent = 'All Checkpoints';
       selector.appendChild(allOption);

       for (const checkpoint of [...allCheckpoints].sort(
         (left, right) => new Date(left.commit_date).getTime() - new Date(right.commit_date).getTime(),
       )) {
         const option = document.createElement('option');
         option.value = checkpoint.checkpoint_id;
         option.textContent = formatCheckpointOptionLabel(checkpoint);
         selector.appendChild(option);
       }

       const nextValue =
         selectedValue !== 'all' && allCheckpoints.some((checkpoint) => checkpoint.checkpoint_id === selectedValue)
           ? selectedValue
           : 'all';

       selector.value = nextValue;
       selector.disabled = allCheckpoints.length === 0;
     }

     function applyCache(cache: CheckpointsCache, selectedValue: string) {
       allCheckpoints = filterRenderableCheckpoints(cache.checkpoints);

       if (dataEl) {
         dataEl.dataset.value = JSON.stringify(allCheckpoints);
       }

       if (repoEl) repoEl.textContent = cache.meta.repo;
       if (branchEl) branchEl.textContent = cache.meta.branch;
       if (countEl) countEl.textContent = String(cache.meta.checkpointCount);
       if (generatedEl) generatedEl.textContent = formatGeneratedAt(cache.meta.generatedAt);

       syncSelector(selectedValue);
       renderDashboard(getSelectedCheckpoints());
     }

     if (selector) {
       selector.addEventListener('change', () => {
         renderDashboard(getSelectedCheckpoints());
       });
     }

     if (refreshButton) {
       const idleLabel = refreshButton.textContent ?? 'Refresh From GitHub';

       refreshButton.addEventListener('click', async () => {
         const selectedValue = selector?.value ?? 'all';

         refreshButton.disabled = true;
         refreshButton.textContent = 'Refreshing...';
         setStatus('Fetching the latest checkpoint data from GitHub...', 'muted');

         try {
           const result = await fetchCheckpointsCache();
           applyCache(result.cache, selectedValue);
           setStatus(
             `Loaded ${result.cache.meta.checkpointCount} checkpoints in ${(result.elapsedMs / 1000).toFixed(1)}s across ${result.apiCallCount} GitHub API calls.`,
             'success',
           );
         } catch (error) {
           const message = error instanceof Error ? error.message : 'Unknown error';
           setStatus(`Refresh failed: ${message}`, 'error');
         } finally {
           refreshButton.disabled = false;
           refreshButton.textContent = idleLabel;
         }
       });
     }
   </script>
 </AiMetricsLayout>

